package genxsolution.vms.vmsbackend.maintenance_management.maintenance_standard.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_standard.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_standard.service.MaintenanceStandardService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/vehicles/maintenance-standards") public class MaintenanceStandardController { private final MaintenanceStandardService service; public MaintenanceStandardController(MaintenanceStandardService service){this.service=service;} @GetMapping public List<MaintenanceStandardResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public MaintenanceStandardResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public MaintenanceStandardResponse create(@RequestBody MaintenanceStandardUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public MaintenanceStandardResponse update(@PathVariable UUID id,@RequestBody MaintenanceStandardUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
